import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input received from a form
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly sanitizing user input by encoding special characters
        String sanitizedInput = Encode.forHtml(userInput);

        // Outputting sanitized input to HTML
        String outputHtml = "<div>" + sanitizedInput + "</div>";

        System.out.println(outputHtml);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
